        text.push_str(&quoted(item));
    }
    text.push_str("]\n");
    text.push_str("    }");
    text
}

fn observation_json(obs: &Observation) -> String {
    format!(
        "        {{\"label\": {}, \"symbol\": {}, \"found\": {}, \"path\": {}, \"source\": {}, \"line\": {}, \"epoch\": {}, \"reused\": {}, \"fresh\": {}}}",
        quoted(&obs.label),
        quoted(&obs.symbol),
